const https = require('https');

function nocoRequest(method, path) {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: 'nocodb.pressco21.com',
      path: '/api/v1/db/data/noco/' + $env.NOCODB_PROJECT_ID + path,
      method: method,
      headers: {
        'xc-token': $env.NOCODB_API_TOKEN,
        'Content-Type': 'application/json'
      }
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); } catch(e) { resolve(data); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

const body = $input.first().json.body || {};
const memberId = body.member_id;

try {
  if (!memberId) {
    return [{json: {success: false, message: 'member_id required', statusCode: 400}}];
  }

  // tbl_Settlements에서 수강생 예약 목록 조회
  const result = await nocoRequest('GET', '/mcoddguv4d3s3ne?where=(student_member_id,eq,' + encodeURIComponent(memberId) + ')&sort=-class_date&limit=50&fields=settlement_id,class_id,class_name,class_date,student_name,student_email,participants,tuition_amount,material_amount,total_amount,status,partner_code,partner_name');
  const list = result.list || [];

  const bookings = list.map(s => ({
    settlement_id: s.settlement_id || '',
    class_id: s.class_id || '',
    class_name: s.class_name || '',
    class_date: s.class_date || '',
    participants: s.participants || 1,
    total_amount: Number(s.total_amount) || 0,
    status: s.status || '',
    partner_name: s.partner_name || ''
  }));

  return [{json: {
    success: true,
    data: { bookings, total: bookings.length },
    statusCode: 200
  }}];

} catch(e) {
  return [{json: {success: false, message: 'Internal error: ' + e.message, statusCode: 500}}];
}
